import { Badge, Col, Divider, Form, Row, Select, Tooltip } from "antd"
import moment from "moment"
import { useEffect, useState } from "react"
import { useSelector } from "react-redux"
import DatePickerCustom from "src/components/Date/DatePickerCustom"
import { FloatActionWrapper } from "src/components/FloatAction/styles"
import InputCustom from "src/components/Input/InputCustom"
import ButtonCustom from "src/components/MyButton/Button"
import ButtonCircle from "src/components/MyButton/ButtonCircle"
import SelectCustom from "src/components/Select/SelectCustom"
import SpinCustom from "src/components/SpinCustom"
import TableCustom from "src/components/Table/CustomTable"
import {
  MainTableData,
  MainTableHeader,
  SubTableData,
  SubTableHeader,
} from "src/components/Table/CustomTable/styled"
import { hideOnSinglePage } from "src/constants/constants"
import { DEFAULT_PAGE_SIZE } from "src/constants/pageSizeOptions"
import { useBadgeCounts } from "src/hooks/useBadgeCounts"
import { getListComboByKey } from "src/lib/utils"
import ContactService from "src/services/ContactService"
import ModalConfirm from "./Modal/ModalConfirm"
import ModalDetailRequest from "./Modal/ModalDetailRequest"
import { StyleRecruitment } from "./styled"

export const statusColor = ["#FF720D", "#00AEAC", "#FF4648"]
const RequestSupport = () => {
  const [form] = Form.useForm()
  const { Option } = Select
  const [loading, setLoading] = useState(false)
  const [pagination, setPagination] = useState({
    CurrentPage: 1,
    PageSize: DEFAULT_PAGE_SIZE,
    TextSearch: "",
    // TopicMain: "",
  })
  const [dataSource, setDataSource] = useState()
  const [rowSelected, setRowSelected] = useState([])
  const [isConfirm, setIsConfirm] = useState(false)
  const [openModalDetailRequest, setOpenModalDetailRequest] = useState(false)
  const { listSystemKey } = useSelector(state => state.appGlobal)
  const { badgeCounts } = useBadgeCounts()
  const pendingRequestsCount = badgeCounts.supportRequest || 0
  const columns = [
    {
      title: "STT",
      dataIndex: "id",
      width: 60,
      align: "center",
      render: (text, row, idx) => (
        <div className="text-center">
          {idx + 1 + pagination.PageSize * (pagination.CurrentPage - 1)}
        </div>
      ),
    },
    {
      title: (
        <div className="text-center">
          <MainTableHeader>Mã yêu cầu</MainTableHeader>
          {/* <SubTableHeader>Chủ đề chính</SubTableHeader> */}
        </div>
      ),
      dataIndex: "RequestCode",
      width: 150,
      render: (text, record) => (
        <Tooltip
          title={
            <div>
              <div>{text}</div>
              {/* <div>{record?.TopicMain}</div> */}
            </div>
          }
        >
          <div className="text-center">
            <MainTableData className="max-line1">{text}</MainTableData>
            {/* <SubTableData className="max-line1">
              {
                // listTopic?.find(item => item?.ID === record?.TopicMain)
                //   ?.Description || "Khác"
                !!(record?.TopicMain === "-1") ? "Khác" : record?.TopicMain
              }
            </SubTableData> */}
          </div>
        </Tooltip>
      ),
    },
    {
      title: (
        <div className="text-center">
          <MainTableHeader>Họ và tên</MainTableHeader>
          <SubTableHeader>Số điện thoại</SubTableHeader>
        </div>
      ),
      dataIndex: "FullName",
      width: 150,
      render: (text, record) => (
        <Tooltip
          title={
            <div>
              <div>Họ và tên: {text}</div>
              <div>Số điện thoại: {record.PhoneNumber}</div>
              <div>Địa chỉ: {record.Address}</div>
            </div>
          }
        >
          <div className="text-center">
            <MainTableData className="max-line1">{text}</MainTableData>
            <SubTableData className="max-line1">
              {record.PhoneNumber}
            </SubTableData>
          </div>
        </Tooltip>
      ),
    },
    {
      title: (
        <div className="text-center">
          <MainTableHeader>Thời gian yêu cầu</MainTableHeader>
          <SubTableHeader>Thời gian hỗ trợ</SubTableHeader>
        </div>
      ),
      dataIndex: "CreateDate",
      width: 180,
      render: (text, record) => (
        <div className="text-center">
          <MainTableData>
            {moment(text).format("DD-MM-YYYY HH:mm")}
          </MainTableData>
          <SubTableData>
            {record?.LastUpdate
              ? moment(record.LastUpdate).format("DD-MM-YYYY HH:mm")
              : "Chưa hỗ trợ"}
          </SubTableData>
        </div>
      ),
    },

    {
      title: "Vấn đề cần hỗ trợ",
      dataIndex: "Content",
      align: "center",
      render: (text, record) => (
        <Tooltip
          title={
            <div style={{ overflow: "auto", maxHeight: "200px" }}>
              <div>{text}</div>
            </div>
          }
        >
          <div className="max-line3">{text}</div>
        </Tooltip>
      ),
    },
    {
      title: "Nội dung đã hỗ trợ/Từ chối",
      dataIndex: "SupportContent",
      align: "center",
      render: (text, record) => (
        <Tooltip
          title={
            <div style={{ overflow: "auto", maxHeight: "200px" }}>
              <div>{text}</div>
            </div>
          }
        >
          {" "}
          <div className="max-line3">{text}</div>
        </Tooltip>
      ),
    },
    {
      title: "Trạng thái",
      dataIndex: "Status",
      align: "center",
      width: 150,
      render: (value, record) => (
        <div className="text-center">
          <div
            style={{ color: `${statusColor[value - 1]}`, fontWeight: "600" }}
          >
            {
              getListComboByKey(
                "SUBMIT_SUPPORT_REQUEST_STATUS",
                listSystemKey,
              )?.find(item => item?.CodeValue === value)?.Description
            }
          </div>
          <FloatActionWrapper size="small" className="float-action__wrapper">
            {!!record?.IsAccept && (
              <ButtonCircle
                title="Xác nhận"
                iconName="check-circle"
                style={{
                  background: "#EDF6FC",
                  boxShadow: "0px 2px 4px rgba(208, 206, 187, 0.5)",
                }}
                onClick={e => {
                  e.stopPropagation()
                  setIsConfirm({ type: 2 })
                  setRowSelected([record])
                }}
              />
            )}
            {!!record?.IsRefuse && (
              <ButtonCircle
                title="Từ chối"
                iconName="cancel"
                style={{
                  background: "#FFE9EC",
                  boxShadow: "0px 2px 4px rgba(208, 206, 187, 0.5)",
                }}
                onClick={e => {
                  e.stopPropagation()
                  setIsConfirm({ type: 3 })
                  setRowSelected([record])
                }}
              />
            )}
            {!!record?.IsRecall && (
              <ButtonCircle
                title="Thu hồi"
                iconName="reply"
                style={{
                  background: "#FFFDE7",
                  boxShadow: "0px 2px 4px rgba(208, 206, 187, 0.5)",
                }}
                onClick={e => {
                  e.stopPropagation()

                  setOpenModalDetailRequest({
                    record: record,
                    ContactID: record?.ContactID,
                  })
                }}
              />
            )}
          </FloatActionWrapper>
        </div>
      ),
    },
  ]

  const getListSuggest = () => {
    setLoading(true)
    const values = form.getFieldsValue()
    ContactService.getList({
      ...pagination,
      ...values,
    })
      .then(res => {
        if (res.isOk) {
          setDataSource(res.Object)
        }
      })
      .finally(() => setLoading(false))
  }

  useEffect(() => {
    // Tìm CodeValue của 'Chưa hỗ trợ' trong listSystemKey
    const statusList =
      getListComboByKey("SUBMIT_SUPPORT_REQUEST_STATUS", listSystemKey) || []
    const defaultStatus = statusList.find(
      item => item.Description === "Chưa hỗ trợ",
    )
    form.setFieldsValue({ Status: defaultStatus ? defaultStatus.CodeValue : 0 })
    // Nếu muốn filter luôn, cập nhật cả pagination
    if (defaultStatus) {
      setPagination(prev => ({ ...prev, Status: defaultStatus.CodeValue }))
    }
  }, [listSystemKey])
  useEffect(() => {
    getListSuggest()
  }, [pagination])

  const handleChangePage = (page, pageSize) => {
    let currentPage = page
    if (pageSize !== pagination.PageSize) {
      currentPage = 1
    }
    setPagination({
      ...pagination,
      CurrentPage: currentPage,
      PageSize: pageSize,
    })
  }

  const rowSelection = {
    preserveSelectedRowKeys: true,
    selectedRowKeys: rowSelected?.map(i => i?.ContactID),
    onChange: (selectedRowKeys, selectedRows) => {
      setRowSelected(selectedRows)
    },
    getCheckboxProps: record => ({
      disabled: record.Status !== 1,
    }),
  }
  const onClickRow = record => {
    if (record.Status !== 1) setRowSelected([])
    else setRowSelected([record])
    setOpenModalDetailRequest({ record: record, ContactID: record?.ContactID })
  }
  return (
    <SpinCustom spinning={loading}>
      <StyleRecruitment>
        <Form form={form} className="rq-support">
          <Row gutter={16}>
            <Col span={12}>
              <Form.Item name="TextSearch">
                <InputCustom
                  type="search"
                  allowClear
                  placeholder="Nhập mã yêu cầu, tên, số điện thoại khách hàng"
                  onSearch={val => {
                    setPagination({
                      ...pagination,
                      CurrentPage: 1,
                      TextSearch: val,
                    })
                  }}
                />
              </Form.Item>
            </Col>
            <Col span={6}>
              <Form.Item name="Date">
                <DatePickerCustom
                  allowClear
                  type="ranger"
                  placeholder={["Từ ngày", "Đến ngày"]}
                  onChange={value => {
                    setPagination(pre => ({
                      ...pre,
                      CurrentPage: 1,
                      FromDate: value ? value[0]?.format() : "",
                      ToDate: value ? value[1]?.format() : "",
                    }))
                  }}
                />
              </Form.Item>
            </Col>
            <Col span={6}>
              <Form.Item name="Status">
                <SelectCustom
                  allowClear
                  placeholder="Trạng thái"
                  onChange={() =>
                    setPagination({
                      ...pagination,
                      CurrentPage: 1,
                    })
                  }
                >
                  <Option key={"allStatusTopicmain"} value={0}>
                    Tất cả
                  </Option>
                  {getListComboByKey(
                    "SUBMIT_SUPPORT_REQUEST_STATUS",
                    listSystemKey,
                  )?.map(i => (
                    <Option key={i.CodeValue} value={i.CodeValue}>
                      {i?.Description}
                    </Option>
                  ))}
                </SelectCustom>
              </Form.Item>
            </Col>
          </Row>
        </Form>
        <Divider />
        <Col
          span={24}
          className="title-type-1 d-flex justify-content-space-between align-items-center pdt0 pt-16 pb-16 mb-16"
        >
          <div
            style={{
              position: "relative",
              display: "flex",
            }}
          >
            <span>Danh sách yêu cầu hỗ trợ</span>
            {pendingRequestsCount > 0 && (
              <Badge
                count={pendingRequestsCount}
                size="small"
                offset={[1, -5]}
                style={{
                  backgroundColor: "#f50",
                  fontSize: "10px",
                }}
              />
            )}
          </div>
          <div style={{ display: "flex" }}>
            <ButtonCustom
              btnType="primary"
              className="btn-hover-shadow"
              style={{ marginRight: "10px" }}
              onClick={() => setIsConfirm({ type: 2 })}
              disabled={!rowSelected.length}
            >
              Xác nhận hỗ trợ
            </ButtonCustom>
            <ButtonCustom
              style={{ marginRight: "8px" }}
              className="btn-hover-shadow"
              btnType="third"
              disabled={!rowSelected.length}
              onClick={() => setIsConfirm({ type: 3 })}
            >
              Từ chối
            </ButtonCustom>
          </div>
        </Col>
        <TableCustom
          isPrimary
          sticky={{ offsetHeader: -12 }}
          onRow={(record, rowIndex) => {
            return {
              onClick: event => {
                onClickRow(record)
              },
            }
          }}
          columns={columns}
          rowSelection={{
            type: "checkbox",
            ...rowSelection,
          }}
          dataSource={dataSource?.GetAll}
          pagination={{
            hideOnSinglePage: dataSource?.Total <= hideOnSinglePage,
            current: pagination.CurrentPage,
            pageSize: pagination.PageSize,
            responsive: true,
            total: dataSource?.Total,
            locale: { items_per_page: "" },
            showSizeChanger: dataSource?.Total > 20,
            onChange: (page, pageSize) => handleChangePage(page, pageSize),
          }}
          rowKey="ContactID"
        />
        {!!isConfirm && (
          <ModalConfirm
            selectedRow={rowSelected}
            open={isConfirm}
            onCancel={() => setIsConfirm(false)}
            onOk={() => {
              setRowSelected([])
              getListSuggest()
            }}
          />
        )}

        {!!openModalDetailRequest && (
          <ModalDetailRequest
            open={openModalDetailRequest}
            onCancel={() => {
              setOpenModalDetailRequest(false)
            }}
            onOk={() => {
              setRowSelected([])
              getListSuggest()
            }}
          />
        )}
      </StyleRecruitment>
    </SpinCustom>
  )
}

export default RequestSupport
