import { Col, Form, Input, Row } from "antd"
import { useEffect, useState } from "react"
import CustomModal from "src/components/Modal/CustomModal"
import ButtonCustom from "src/components/MyButton/Button"
import Notice from "src/components/Notice"
import SpinCustom from "src/components/SpinCustom"
import ContactService from "src/services/ContactService"
import CommentRefuse from "../component/CommentRefuse"
import {
  StyleModalDetailRequest,
  StyleModalDetailRequestFooter,
} from "../styled"
import InforRequest from "./InforRequest"

export const COLOR = ["#00AEAC", "#FF4648", "#172B4D"]
const ModalDetailRequest = ({ open, onCancel, onOk }) => {
  const [loading, setLoading] = useState()
  const [detailContact, setDetailContact] = useState()
  const getDetailContact = async () => {
    try {
      setLoading(true)
      const res = await ContactService.getDetailContact({
        ContactID: open?.ContactID,
      })
      if (res?.isError) return
      setDetailContact(res?.Object)
    } finally {
      setLoading(false)
    }
  }
  useEffect(() => {
    getDetailContact()
  }, [])

  const [form] = Form.useForm()

  const handleSubmit = status => {
    const value = form.getFieldsValue()
    setLoading(true)
    let object = {
      lstContactID: [open?.ContactID],
      Status: status,
      SupportContent: value?.Note,
    }

    ContactService.confirmSupport(object)
      .then(res => {
        if (res.isOk) {
          Notice({ msg: "Cập nhật thành công" })
          onCancel()
          onOk()
        }
      })
      .finally(() => setLoading(false))
  }

  const renderFooter = () => {
    return (
      <StyleModalDetailRequestFooter>
        <Col span={24}>
          <div className="spb">
            <div className="fle">
              {!!open?.record?.IsAccept && (
                <ButtonCustom
                  loading={loading}
                  btnType="primary"
                  className="btn-hover-shadow"
                  onClick={() => handleSubmit(2)}
                >
                  Xác nhận hỗ trợ
                </ButtonCustom>
              )}
              {!!open?.record?.IsRefuse && (
                <ButtonCustom
                  loading={loading}
                  style={{ marginLeft: "8px" }}
                  className="btn-hover-shadow"
                  btnType="third"
                  onClick={() => handleSubmit(3)}
                >
                  Từ chối
                </ButtonCustom>
              )}
            </div>
          </div>
        </Col>
      </StyleModalDetailRequestFooter>
    )
  }
  const renderFooter2 = () => {
    return (
      <StyleModalDetailRequestFooter>
        <Col span={24}>
          <div className="spb">
            <div></div>
            <div className="fle">
              {!!open?.record?.IsRecall && (
                <ButtonCustom
                  loading={loading}
                  style={{ marginLeft: "8px" }}
                  className="btn-hover-shadow"
                  btnType="primary"
                  onClick={() => {
                    handleSubmit(4)
                  }}
                >
                  Thu hồi
                </ButtonCustom>
              )}
            </div>
          </div>
        </Col>
      </StyleModalDetailRequestFooter>
    )
  }
  return (
    <CustomModal
      open={!!open}
      onCancel={onCancel}
      width={1024}
      title={`Chi tiết phiếu yêu cầu hỗ trợ`}
      footer={open?.record?.Status === 1 ? renderFooter() : renderFooter2()}
    >
      <StyleModalDetailRequest>
        <SpinCustom spinning={loading}>
          <Row gutter={[16, 16]}>
            <Col span={24}>
              <InforRequest detailContact={detailContact} />
            </Col>
            <Col span={24}>
              <CommentRefuse />
            </Col>
            <Col span={24}>
              {detailContact?.Status === 1 && (
                <Form form={form} layout="vertical">
                  <Form.Item label="Ý kiến xử lý" name="Note">
                    <Input.TextArea placeholder="Nhập nội dung" rows={5} />
                  </Form.Item>
                </Form>
              )}
            </Col>
          </Row>
        </SpinCustom>
      </StyleModalDetailRequest>
    </CustomModal>
  )
}

export default ModalDetailRequest
